class Solution: 
 def __init__(self): 
 self.root = TrieNode() 
 def insert(self, word): 
 node = self.root 
 for ch in word: 
 if not hasattr(node, ch): 
 setattr(node, ch, TrieNode()) 
 node = getattr(node, ch) 
 def count_leafs(self): 
 count = 0 
 for node in self.root.__dict__.values(): 
 if not hasattr(node, 'children') and not hasattr(node, 'parent'): 
 count++ 
 return count 

 # Read input from standard input 
 import sys 
 lines = sys.stdin.read().split('\n') 
 words = [line for line in lines if line] 
 solution = Solution() 
 for word in words: 
 solution.insert(word) 
 print(solution.count_leafs())

