#include <vector> #include <iostream> #include <string> using namespace std; 
 class TrieNode { public: TrieNode* children[26]; TrieNode* parent; }; 
 class Solution { public: TrieNode* root; 
 void insert(string word) { TrieNode* node = root; 
 for (char ch : word) { 
 int index = ch - 'a'; 
 if (!node->children[index]) 
 node->children[index] = new TrieNode(); 
 node = node->children[index]; 
 } 
 } 
 int countLeafs() { 
 int count = 0; 
 for (TrieNode* node : nodes) { 
 if (!node->parent && !node->children[0]) 
 count++; 
 } 
 return count; 
 }; 

